window.addEventListener("load",function(){const t=document.getElementById("jb-burger-btn"),n=document.getElementById("jb-close-menu"),e=document.getElementById("jb-mobile-menu");if(t&&n&&e){const o=function(){e.classList.remove("hidden"),window.setTimeout(function(){e.classList.remove("translate-x-full")},10),document.body.style.overflow="hidden",t.setAttribute("aria-expanded","true")},d=function(){e.classList.add("translate-x-full"),t.setAttribute("aria-expanded","false"),document.body.style.overflow="",window.setTimeout(function(){e.classList.add("hidden")},300)};t.addEventListener("click",function(){o()}),n.addEventListener("click",function(){d()})}})